import React, { useState } from 'react'

function App1() {
    const [timer,settimer]=useState(0)

    const start=()=>{
        setTimeout(()=>{
            settimer(timer+1);
        },1000)
    }

    const stop=()=>{
        setTimeout(() => {
         settimer(0)   
        });
    }

  return (
    <div>

        <h2>{timer}</h2>
        <button onClick={start}>start</button>
        <button onClick={stop}>stop</button>


    </div>
  )
}

export default App1
